import React, { useRef, useState, useMemo } from 'react';
import { Key, Users, Search, X, Smartphone, Printer, Share2, CalendarDays, FileDown, ChevronLeft, ChevronRight, Zap, ShieldCheck, Quote } from 'lucide-react';
import { AppDataV1, Culto } from '../types';
import { MONTHS, DAYS_SHORT } from '../constants';

interface Props {
  data: AppDataV1;
}

const RelatorioTab: React.FC<Props> = ({ data }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [filterName, setFilterName] = useState('');
  const [viewMode, setViewMode] = useState<'print' | 'mobile' | 'weekly'>('weekly');
  const [selectedWeek, setSelectedWeek] = useState(0);

  const reportRef = useRef<HTMLDivElement>(null);
  const mobileRef = useRef<HTMLDivElement>(null);
  const weeklyRef = useRef<HTMLDivElement>(null);

  const WHATSAPP_MESSAGE = "Paz, obreiros. Segue a escala. Deus abençoe!";

  const getWorkerDisplayName = (id: string | undefined) => {
    if (!id) return '---';
    const obreiro = data.obreiros.find(o => o.id === id);
    if (!obreiro) return '---';
    const name = obreiro.name.split(' ')[0] + (obreiro.name.split(' ')[1] ? ' ' + obreiro.name.split(' ')[1][0] + '.' : '');
    return `${obreiro.role} ${name}`.toUpperCase();
  };

  const sortedCultos = useMemo(() => {
    return [...data.cultos]
      .sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time))
      .filter(culto => {
        if (!filterName) return true;
        const f = filterName.toLowerCase();
        const getObreiroName = (id: string) => data.obreiros.find(o => o.id === id)?.name.toLowerCase() || '';
        const namesInCulto = [
          ...culto.workersAbertura.map(getObreiroName), 
          ...culto.workersApoio.map(getObreiroName), 
          getObreiroName(culto.santaCeiaWorkers?.arrumarMesa || ''), 
          getObreiroName(culto.santaCeiaWorkers?.desarrumarMesa || ''), 
          getObreiroName(culto.santaCeiaWorkers?.servirPao || ''), 
          getObreiroName(culto.santaCeiaWorkers?.servirVinho || '')
        ];
        return namesInCulto.some(name => name.includes(f));
      });
  }, [data.cultos, data.obreiros, filterName]);

  const weeks = useMemo(() => {
    if (sortedCultos.length === 0) return [];
    const weeksMap = new Map<string, Culto[]>();
    sortedCultos.forEach(culto => {
      const d = new Date(culto.date + "T12:00:00");
      const day = d.getDay(); 
      const diffToMonday = day === 0 ? 6 : day - 1;
      const monday = new Date(d);
      monday.setDate(d.getDate() - diffToMonday);
      const weekKey = monday.toISOString().split('T')[0];
      if (!weeksMap.has(weekKey)) weeksMap.set(weekKey, []);
      weeksMap.get(weekKey)?.push(culto);
    });
    return Array.from(weeksMap.keys()).sort().map(key => weeksMap.get(key) || []);
  }, [sortedCultos]);

  const cultosToShow = viewMode === 'weekly' ? (weeks[selectedWeek] || []) : sortedCultos;

  const weekRangeLabel = useMemo(() => {
    if (viewMode !== 'weekly' || !cultosToShow.length) return "";
    const baseDate = new Date(cultosToShow[0].date + "T12:00:00");
    const day = baseDate.getDay();
    const diffToMonday = day === 0 ? 6 : day - 1;
    const mon = new Date(baseDate);
    mon.setDate(baseDate.getDate() - diffToMonday);
    const sun = new Date(mon);
    sun.setDate(mon.getDate() + 6);
    const mStart = MONTHS[mon.getMonth()].toUpperCase();
    if (mon.getMonth() !== sun.getMonth()) return `${mon.getDate()}/${mon.getMonth()+1} a ${sun.getDate()}/${sun.getMonth()+1}`;
    return `${mon.getDate()} a ${sun.getDate()} DE ${mStart}`;
  }, [cultosToShow, viewMode]);

  const handleExportPDF = () => {
    const element = viewMode === 'print' ? reportRef.current : (viewMode === 'mobile' ? mobileRef.current : weeklyRef.current);
    if (!element) return;
    setIsExporting(true);
    const filename = `ESCALA_ADFARE_${viewMode.toUpperCase()}.pdf`;
    const opt = {
      margin: [5, 5],
      filename: filename,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true },
      jsPDF: { unit: 'px', format: viewMode === 'print' ? 'a4' : [400, 800], orientation: 'portrait' }
    };
    // @ts-ignore
    if (typeof html2pdf !== 'undefined') {
      // @ts-ignore
      html2pdf().from(element).set(opt).save().then(() => setIsExporting(false)).catch(() => setIsExporting(false));
    } else {
      setIsExporting(false);
    }
  };

  const handleExportImage = async () => {
    const element = viewMode === 'weekly' ? weeklyRef.current : mobileRef.current;
    if (!element) return;
    setIsExporting(true);

    // @ts-ignore
    if (typeof html2canvas !== 'undefined') {
      // @ts-ignore
      html2canvas(element, {
        scale: 3,
        useCORS: true,
        backgroundColor: "#ffffff",
        logging: false,
        width: 400,
      }).then(async (canvas) => {
        const fileName = `ESCALA_ADFARE_${viewMode.toUpperCase()}.png`;
        canvas.toBlob(async (blob: Blob | null) => {
          if (!blob) { setIsExporting(false); return; }
          const file = new File([blob], fileName, { type: 'image/png' });
          // @ts-ignore
          if (navigator.canShare && navigator.canShare({ files: [file] })) {
            try { await navigator.share({ files: [file], title: 'Escala ADFARE', text: WHATSAPP_MESSAGE }); } 
            catch (err) { downloadImage(canvas, fileName); }
          } else {
            downloadImage(canvas, fileName);
            window.open(`https://wa.me/?text=${encodeURIComponent(WHATSAPP_MESSAGE)}`, '_blank');
          }
          setIsExporting(false);
        }, 'image/png');
      }).catch(() => setIsExporting(false));
    } else {
      setIsExporting(false);
    }
  };

  const downloadImage = (canvas: HTMLCanvasElement, fileName: string) => {
    const link = document.createElement('a');
    link.download = fileName;
    link.href = canvas.toDataURL('image/png', 1.0);
    link.click();
  };

  const renderDigitalLayout = (ref: React.RefObject<HTMLDivElement>, id: string, title: string, dateLabel: string, cultos: Culto[]) => (
    <div 
      ref={ref} 
      id={id} 
      className="bg-white w-full max-w-[400px] mx-auto flex flex-col p-4 shadow-sm relative overflow-hidden rounded-[24px] border border-slate-100"
    >
      <div className="bg-blue-950 rounded-[24px] p-5 text-white mb-6 border-b-4 border-blue-600 shadow-lg">
        <div className="flex justify-between items-center mb-4">
          <div className="flex flex-col">
            <span className="text-[8px] font-black tracking-[0.2em] text-blue-400 uppercase leading-none mb-1">{title}</span>
            <h1 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none">ADFARE</h1>
          </div>
          <div className="bg-blue-900 p-2 rounded-lg border border-blue-800"><CalendarDays size={16} className="text-blue-300" /></div>
        </div>
        <div className="bg-white/10 backdrop-blur-sm rounded-xl p-2.5 border border-white/10 text-center">
          <span className="text-sm font-black uppercase tracking-tight text-white block">
            {dateLabel}
          </span>
        </div>
      </div>

      <div className="space-y-3 mb-6">
        {cultos.length === 0 ? (
          <div className="py-10 text-center text-slate-300 font-black uppercase text-[10px] italic tracking-widest">Vazio</div>
        ) : (
          cultos.map((culto) => (
            <div key={culto.id} className={`rounded-[20px] p-3 shadow-sm border ${culto.isSantaCeia ? 'bg-purple-900 border-purple-800 text-white' : 'bg-slate-50 border-slate-100'}`}>
              <div className="flex items-center gap-3">
                <div className={`w-12 h-12 rounded-xl flex flex-col items-center justify-center shrink-0 shadow-sm ${culto.isSantaCeia ? 'bg-white text-purple-900' : 'bg-blue-900 text-white'}`}>
                  <span className="text-[7px] font-black opacity-60 uppercase">{DAYS_SHORT[culto.dayOfWeek]}</span>
                  <span className="text-xl font-black leading-none">{culto.date.split('-')[2]}</span>
                </div>
                <div className="flex-grow min-w-0">
                  <div className="flex justify-between items-center mb-1.5">
                    <h4 className={`text-[11px] font-black uppercase truncate pr-2 ${culto.isSantaCeia ? 'text-white' : 'text-slate-800'}`}>{culto.isSantaCeia ? '★ CEIA' : culto.name}</h4>
                    <span className={`shrink-0 text-[9px] font-black px-2 py-0.5 rounded-md ${culto.isSantaCeia ? 'bg-purple-800 text-white' : 'bg-white text-blue-900'}`}>{culto.time}H</span>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div className={`p-1.5 rounded-lg flex items-center gap-1.5 min-w-0 ${culto.isSantaCeia ? 'bg-white/10' : 'bg-white'}`}>
                      <Key size={10} className={culto.isSantaCeia ? 'text-purple-300' : 'text-blue-600'} />
                      <span className="text-[9px] font-black uppercase truncate">{getWorkerDisplayName(culto.workersAbertura[0])}</span>
                    </div>
                    <div className={`p-1.5 rounded-lg flex items-center gap-1.5 min-w-0 ${culto.isSantaCeia ? 'bg-white/10' : 'bg-white'}`}>
                      <Users size={10} className={culto.isSantaCeia ? 'text-purple-300' : 'text-emerald-600'} />
                      <span className="text-[9px] font-black uppercase truncate">{getWorkerDisplayName(culto.workersApoio[0])}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )
        ))}
      </div>

      <div className="bg-blue-50/50 rounded-xl p-3 border border-blue-100 relative mb-4">
        <p className="text-[10px] font-bold text-slate-700 italic leading-tight text-center">
          "Sede firmes e constantes, sempre abundantes na obra do Senhor."
        </p>
      </div>

      <div className="text-center opacity-40">
        <span className="text-[7px] font-black text-slate-500 uppercase tracking-[0.3em]">FAMÍLIA RESTAURADA</span>
      </div>
    </div>
  );

  return (
    <div className="space-y-4 pb-20">
      <div className="bg-white p-3 rounded-2xl shadow-sm border border-slate-100 no-print space-y-3">
        <div className="flex flex-col gap-2">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
            <input type="text" placeholder="Buscar..." value={filterName} onChange={e => setFilterName(e.target.value)} className="w-full pl-9 pr-8 py-2.5 bg-slate-50 border border-slate-100 rounded-xl font-bold text-sm text-slate-900 outline-none" />
          </div>
          <div className="flex bg-slate-100 p-1 rounded-xl">
            <button onClick={() => setViewMode('weekly')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase flex items-center justify-center gap-1.5 transition-all ${viewMode === 'weekly' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}><Zap size={14} /> Semana</button>
            <button onClick={() => setViewMode('mobile')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase flex items-center justify-center gap-1.5 transition-all ${viewMode === 'mobile' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}><Smartphone size={14} /> Mês</button>
            <button onClick={() => setViewMode('print')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase flex items-center justify-center gap-1.5 transition-all ${viewMode === 'print' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}><Printer size={14} /> Mural</button>
          </div>
        </div>
        {viewMode === 'weekly' && weeks.length > 0 && (
          <div className="flex items-center justify-between bg-blue-50 p-2 rounded-xl border border-blue-100">
            <button disabled={selectedWeek === 0} onClick={() => setSelectedWeek(w => Math.max(0, w - 1))} className="p-2 text-blue-900 disabled:opacity-20"><ChevronLeft size={20} /></button>
            <div className="text-center px-2 min-w-0">
              <span className="text-[10px] font-black text-blue-900 uppercase leading-none">Semana {selectedWeek + 1}</span>
              <p className="text-[8px] font-bold text-blue-400 uppercase mt-0.5 truncate">{weekRangeLabel}</p>
            </div>
            <button disabled={selectedWeek === weeks.length - 1} onClick={() => setSelectedWeek(w => Math.min(weeks.length - 1, w + 1))} className="p-2 text-blue-900 disabled:opacity-20"><ChevronRight size={20} /></button>
          </div>
        )}
        <div className="grid grid-cols-2 gap-2">
          <button onClick={handleExportPDF} disabled={isExporting || cultosToShow.length === 0} className="py-3 bg-blue-900 text-white rounded-xl font-black flex items-center justify-center gap-2 text-[10px] uppercase shadow-md disabled:opacity-50">
            {isExporting ? '...' : <FileDown size={14} />} PDF
          </button>
          <button onClick={handleExportImage} disabled={isExporting || cultosToShow.length === 0 || viewMode === 'print'} className="py-3 bg-emerald-600 text-white rounded-xl font-black flex items-center justify-center gap-2 text-[10px] uppercase shadow-md disabled:opacity-50">
            {isExporting ? '...' : <Share2 size={14} />} IMAGEM
          </button>
        </div>
      </div>

      <div className="w-full flex justify-center px-1">
        {viewMode === 'weekly' && renderDigitalLayout(weeklyRef, 'weekly-export', 'ESCALA DA SEMANA', weekRangeLabel || '---', cultosToShow)}
        {viewMode === 'mobile' && renderDigitalLayout(mobileRef, 'mobile-export', 'ESCALA MENSAL', `${MONTHS[data.currentMonth].toUpperCase()}`, sortedCultos)}
        {viewMode === 'print' && (
          <div className="w-full overflow-x-auto pb-10">
            <div className="bg-white border border-slate-200 p-6 mx-auto rounded-xl" style={{ width: '794px', minHeight: '1123px' }} ref={reportRef}>
               <div className="border-b-4 border-blue-900 pb-4 mb-6 flex justify-between items-end">
                  <h1 className="text-4xl font-black italic text-blue-950">ADFARE</h1>
                  <span className="text-lg font-black uppercase bg-blue-900 text-white px-4 py-1 rounded-full">{MONTHS[data.currentMonth]} {data.currentYear}</span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  {sortedCultos.map(culto => (
                    <div key={culto.id} className="border border-slate-100 p-4 rounded-xl flex items-center gap-4 bg-slate-50">
                      <div className="w-14 h-14 bg-blue-900 text-white flex flex-col items-center justify-center rounded-xl shrink-0">
                        <span className="text-[9px] font-bold">{DAYS_SHORT[culto.dayOfWeek]}</span>
                        <span className="text-2xl font-black">{culto.date.split('-')[2]}</span>
                      </div>
                      <div className="min-w-0">
                        <p className="text-[10px] font-black text-blue-950 uppercase truncate">{culto.name}</p>
                        <p className="text-[11px] font-bold text-slate-700">AB: {getWorkerDisplayName(culto.workersAbertura[0])}</p>
                        <p className="text-[11px] font-bold text-slate-700">AP: {getWorkerDisplayName(culto.workersApoio[0])}</p>
                      </div>
                    </div>
                  ))}
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default RelatorioTab;

import React, { useState, useEffect } from 'react';
import { UserPlus, CalendarDays, ClipboardList, Database, Download, Upload, Trash2, Save, FolderOpen, X, History } from 'lucide-react';
import { AppDataV1, Obreiro, SavedScale } from './types';
import ObreirosTab from './components/ObreirosTab';
import GerenciarMesTab from './components/GerenciarMesTab';
import RelatorioTab from './components/RelatorioTab';
import { MONTHS } from './constants';

const LOCAL_STORAGE_KEY = 'adfare_system_v1';

const INITIAL_OBREIROS: Obreiro[] = [
  { id: 'init-1', name: 'Ana Paula', role: 'Ob.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-2', name: 'Lais', role: 'Ob.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-3', name: 'Miriam', role: 'Ob.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-4', name: 'Vinicius', role: 'Dc.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-5', name: 'Ednaldo', role: 'Dc.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-6', name: 'Robertinho', role: 'Dc.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-7', name: 'Roberto Pai', role: 'Dc.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-8', name: 'Junior', role: 'Dc.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-9', name: 'Alexandre', role: 'Dc.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-10', name: 'Ruan', role: 'Dc.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-11', name: 'Suzana', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-12', name: 'Priscila', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-13', name: 'Quesia', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-14', name: 'Luzinete', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-15', name: 'Flávia', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-16', name: 'Taiane', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-17', name: 'Tatiane', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-18', name: 'Brenda', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-19', name: 'Alexia', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
  { id: 'init-20', name: 'Andreia', role: 'Dca.', preferredRole: 'ambos', balance: 0, fixedDays: [], restrictions: [] },
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'obreiros' | 'mes' | 'relatorio'>('obreiros');
  const [data, setData] = useState<AppDataV1>({
    obreiros: INITIAL_OBREIROS,
    cultos: [],
    currentMonth: new Date().getMonth(),
    currentYear: new Date().getFullYear(),
    savedScales: []
  });
  const [showBackupMenu, setShowBackupMenu] = useState(false);
  const [showLibrary, setShowLibrary] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem(LOCAL_STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setData(prev => ({
          ...prev,
          ...parsed,
          obreiros: parsed.obreiros || prev.obreiros,
          savedScales: parsed.savedScales || []
        }));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data));
  }, [data]);

  const handleExportBackup = () => {
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `backup_adfare_completo_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
    setShowBackupMenu(false);
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const importedData = JSON.parse(event.target?.result as string);
        if (importedData.obreiros) {
          setData(importedData);
          alert("Backup restaurado!");
        }
      } catch (e) {
        alert("Erro no arquivo.");
      }
    };
    reader.readAsText(file);
    setShowBackupMenu(false);
    e.target.value = '';
  };

  const handleResetBalances = () => {
    if (window.confirm("Zerar saldos?")) {
      setData(prev => ({
        ...prev,
        obreiros: prev.obreiros.map(o => ({ ...o, balance: 0 }))
      }));
    }
    setShowBackupMenu(false);
  };

  const saveCurrentScaleToLibrary = () => {
    if (data.cultos.length === 0) return alert("Nada para salvar.");
    const name = prompt("Nome da escala:", `${MONTHS[data.currentMonth]} ${data.currentYear}`);
    if (!name) return;

    const newSaved: SavedScale = {
      id: crypto.randomUUID(),
      name,
      createdAt: new Date().toLocaleString(),
      month: data.currentMonth,
      year: data.currentYear,
      cultos: JSON.parse(JSON.stringify(data.cultos)),
      obreiros: JSON.parse(JSON.stringify(data.obreiros))
    };

    setData(prev => ({
      ...prev,
      savedScales: [newSaved, ...prev.savedScales]
    }));
    setShowBackupMenu(false);
  };

  const loadScaleFromLibrary = (scale: SavedScale) => {
    if (confirm(`Substituir dados atuais?`)) {
      setData(prev => ({
        ...prev,
        currentMonth: scale.month,
        currentYear: scale.year,
        cultos: JSON.parse(JSON.stringify(scale.cultos)),
        obreiros: JSON.parse(JSON.stringify(scale.obreiros || prev.obreiros))
      }));
      setShowLibrary(false);
      setActiveTab('mes');
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-slate-50">
      <header className="bg-blue-950 text-white px-4 py-3 shadow-md no-print sticky top-0 z-50">
        <div className="max-w-4xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <h1 className="text-lg font-black tracking-tighter italic uppercase leading-none">ADFARE</h1>
            <div className="h-4 w-[1px] bg-blue-800"></div>
            <span className="text-[8px] font-black text-blue-400 tracking-widest uppercase">ESCALA</span>
          </div>
          <div className="relative">
            <button 
              onClick={() => setShowBackupMenu(!showBackupMenu)} 
              className={`p-2 rounded-xl transition-all ${showBackupMenu ? 'bg-blue-600' : 'hover:bg-blue-900'}`}
            >
              <Database size={18} />
            </button>
            {showBackupMenu && (
              <div className="absolute right-0 mt-2 w-56 bg-white rounded-2xl shadow-2xl py-2 text-gray-800 border border-slate-100 animate-in fade-in slide-in-from-top-2 z-[60]">
                <button onClick={saveCurrentScaleToLibrary} className="w-full text-left px-4 py-2.5 hover:bg-blue-50 flex items-center gap-3">
                  <Save size={14} className="text-blue-600" />
                  <span className="text-xs font-bold">Salvar Snapshot</span>
                </button>
                <button onClick={() => { setShowLibrary(true); setShowBackupMenu(false); }} className="w-full text-left px-4 py-2.5 hover:bg-blue-50 flex items-center gap-3">
                  <History size={14} className="text-emerald-600" />
                  <span className="text-xs font-bold">Biblioteca</span>
                </button>
                <div className="border-t border-slate-50 my-1"></div>
                <button onClick={handleExportBackup} className="w-full text-left px-4 py-2.5 hover:bg-slate-50 flex items-center gap-3">
                  <Download size={14} className="text-slate-500" />
                  <span className="text-xs font-bold">Exportar Backup</span>
                </button>
                <label className="w-full text-left px-4 py-2.5 hover:bg-slate-50 flex items-center gap-3 cursor-pointer">
                  <Upload size={14} className="text-slate-500" />
                  <span className="text-xs font-bold">Importar Backup</span>
                  <input type="file" className="hidden" accept=".json" onChange={handleImportBackup} />
                </label>
                <div className="border-t border-slate-50 my-1"></div>
                <button onClick={handleResetBalances} className="w-full text-left px-4 py-2.5 hover:bg-rose-50 text-rose-600 flex items-center gap-3">
                  <Trash2 size={14} />
                  <span className="text-xs font-black uppercase">Zerar Saldos</span>
                </button>
              </div>
            )}
          </div>
        </div>
      </header>

      <nav className="bg-white border-b no-print sticky top-[52px] z-40 shadow-sm">
        <div className="max-w-4xl mx-auto flex">
          {[
            { id: 'obreiros', label: 'OBREIROS', icon: UserPlus },
            { id: 'mes', label: 'ESCALAR', icon: CalendarDays },
            { id: 'relatorio', label: 'MURAL', icon: ClipboardList }
          ].map(tab => (
            <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex-1 py-3 text-[9px] font-black tracking-widest border-b-2 transition-all flex flex-col items-center gap-1 ${activeTab === tab.id ? 'border-blue-900 text-blue-900 bg-blue-50/20' : 'border-transparent text-slate-400'}`}
            >
              <tab.icon size={18} />
              {tab.label}
            </button>
          ))}
        </div>
      </nav>

      <main className="flex-grow max-w-4xl mx-auto w-full p-3 pb-20">
        {activeTab === 'obreiros' && <ObreirosTab data={data} setData={setData} />}
        {activeTab === 'mes' && <GerenciarMesTab data={data} setData={setData} />}
        {activeTab === 'relatorio' && <RelatorioTab data={data} />}
      </main>

      {showLibrary && (
        <div className="fixed inset-0 z-[100] bg-slate-950/70 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[85vh]">
            <div className="p-5 bg-slate-900 text-white flex justify-between items-center shrink-0">
              <h3 className="font-black uppercase text-sm tracking-tight">Biblioteca</h3>
              <button onClick={() => setShowLibrary(false)} className="p-2 hover:bg-white/10 rounded-lg"><X size={20} /></button>
            </div>
            <div className="p-3 overflow-y-auto space-y-2 flex-grow bg-slate-50">
              {data.savedScales.length === 0 ? (
                <div className="text-center py-10 text-slate-300 text-xs font-black uppercase">Vazio</div>
              ) : (
                data.savedScales.map(scale => (
                  <div key={scale.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex items-center justify-between">
                    <div className="min-w-0 pr-2">
                      <span className="text-[8px] font-black bg-blue-100 text-blue-600 px-2 py-0.5 rounded-full uppercase mb-1 inline-block">
                        {MONTHS[scale.month]}
                      </span>
                      <h4 className="font-black text-slate-800 text-sm truncate uppercase tracking-tighter">{scale.name}</h4>
                    </div>
                    <div className="flex gap-1">
                      <button onClick={() => loadScaleFromLibrary(scale)} className="p-2.5 bg-emerald-50 text-emerald-600 rounded-xl"><FolderOpen size={16} /></button>
                      <button onClick={() => {
                        if(confirm("Excluir?")) setData(prev => ({...prev, savedScales: prev.savedScales.filter(s => s.id !== scale.id)}))
                      }} className="p-2.5 bg-rose-50 text-rose-400 rounded-xl"><Trash2 size={16} /></button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      <footer className="no-print fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-sm border-t p-2 text-center text-[8px] font-black text-slate-300 uppercase tracking-widest z-30">
        ADFARE &copy; {new Date().getFullYear()}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { CalendarDays, Plus, Trash2, Wand2, Key, Users, X, Wine, RefreshCw, Search, Link as LinkIcon, ChevronLeft, ChevronRight } from 'lucide-react';
import { AppDataV1, Culto, Obreiro } from '../types';
import { MONTHS, DEFAULT_CULTOS, DAYS_FULL } from '../constants';

interface Props {
  data: AppDataV1;
  setData: React.Dispatch<React.SetStateAction<AppDataV1>>;
}

const GerenciarMesTab: React.FC<Props> = ({ data, setData }) => {
  const [showAddManual, setShowAddManual] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showPicker, setShowPicker] = useState<{ cultoId: string, role: string } | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [newCulto, setNewCulto] = useState({
    date: '',
    time: '19:30',
    name: '',
    isSantaCeia: false
  });

  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 5 }, (_, i) => currentYear - 1 + i);

  // Filtra os cultos pertencentes APENAS ao mês/ano selecionados para exibição
  const cultosDoMes = useMemo(() => {
    return data.cultos.filter(c => {
      const d = new Date(c.date + "T12:00:00");
      return d.getMonth() === data.currentMonth && d.getFullYear() === data.currentYear;
    }).sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time));
  }, [data.cultos, data.currentMonth, data.currentYear]);

  // Calcula o saldo baseado em TODO o histórico (essencial para continuidade)
  const calculateGlobalBalances = (obreiros: Obreiro[], allCultos: Culto[]): Obreiro[] => {
    return obreiros.map(obreiro => {
      const count = allCultos.reduce((acc, culto) => {
        const isAbertura = culto.workersAbertura.includes(obreiro.id);
        const isApoio = culto.workersApoio.includes(obreiro.id);
        return acc + (isAbertura ? 1 : 0) + (isApoio ? 1 : 0);
      }, 0);
      return { ...obreiro, balance: count };
    });
  };

  const updateDataWithNewCultos = (newAllCultos: Culto[]) => {
    setData(prev => ({
      ...prev,
      cultos: newAllCultos,
      obreiros: calculateGlobalBalances(prev.obreiros, newAllCultos)
    }));
  };

  const handleMonthChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setData(prev => ({ ...prev, currentMonth: parseInt(e.target.value) }));
  };

  const handleYearChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    setData(prev => ({ ...prev, currentYear: parseInt(e.target.value) }));
  };

  const handleGenerateBase = () => {
    const daysInMonth = new Date(data.currentYear, data.currentMonth + 1, 0).getDate();
    const generated: Culto[] = [];

    // Verifica se já existem cultos neste mês para evitar duplicidade
    if (cultosDoMes.length > 0 && !confirm("Já existem cultos neste mês. Deseja adicionar a base padrão aos que já existem?")) return;

    for (let day = 1; day <= daysInMonth; day++) {
      const date = new Date(data.currentYear, data.currentMonth, day);
      const dateStr = date.toISOString().split('T')[0];
      const dayOfWeek = date.getDay();

      const dayCultos = DEFAULT_CULTOS.filter(c => c.day === dayOfWeek);
      dayCultos.forEach(c => {
        // Evita duplicar o mesmo culto no mesmo horário
        const exists = data.cultos.find(ex => ex.date === dateStr && ex.time === c.time);
        if (!exists) {
          generated.push({
            id: crypto.randomUUID(),
            date: dateStr,
            dayOfWeek,
            time: c.time,
            name: c.name,
            isSantaCeia: false,
            workersAbertura: [],
            workersApoio: [],
            santaCeiaWorkers: { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }
          });
        }
      });
    }

    updateDataWithNewCultos([...data.cultos, ...generated]);
  };

  const handleClearMonth = () => {
    if (cultosDoMes.length === 0) return;
    if (!confirm(`Remover todos os ${cultosDoMes.length} cultos de ${MONTHS[data.currentMonth]}?`)) return;

    // Mantém apenas os cultos que NÃO são do mês atual
    const others = data.cultos.filter(c => {
      const d = new Date(c.date + "T12:00:00");
      return d.getMonth() !== data.currentMonth || d.getFullYear() !== data.currentYear;
    });

    updateDataWithNewCultos(others);
  };

  const handleAddManual = () => {
    if (!newCulto.date || !newCulto.name) return alert("Preencha a data e o nome.");
    const dateObj = new Date(newCulto.date + "T12:00:00");
    const culto: Culto = {
      id: crypto.randomUUID(),
      date: newCulto.date,
      dayOfWeek: dateObj.getDay(),
      time: newCulto.time,
      name: newCulto.name,
      isSantaCeia: newCulto.isSantaCeia,
      workersAbertura: [],
      workersApoio: [],
      santaCeiaWorkers: { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }
    };
    updateDataWithNewCultos([...data.cultos, culto]);
    setNewCulto({ date: '', time: '19:30', name: '', isSantaCeia: false });
    setShowAddManual(false);
  };

  const assignWorker = (cultoId: string, obreiroId: string, role: string) => {
    const obreiro = data.obreiros.find(o => o.id === obreiroId);
    const updatedAll = data.cultos.map(c => {
      if (c.id !== cultoId) return c;

      let workersAbertura = [...c.workersAbertura];
      let workersApoio = [...c.workersApoio];

      if (role === 'abertura') {
        workersAbertura = [obreiroId];
        if (obreiro?.linkedWorkerId && workersApoio.length === 0) workersApoio = [obreiro.linkedWorkerId];
      } else if (role === 'apoio') {
        workersApoio = [obreiroId];
        if (obreiro?.linkedWorkerId && workersAbertura.length === 0) workersAbertura = [obreiro.linkedWorkerId];
      } else {
        return { ...c, santaCeiaWorkers: { ...(c.santaCeiaWorkers || { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }), [role]: obreiroId } };
      }

      return { ...c, workersAbertura, workersApoio };
    });

    updateDataWithNewCultos(updatedAll);
    setShowPicker(null);
  };

  const removeWorker = (cultoId: string, obreiroId: string, role: string) => {
    const updatedAll = data.cultos.map(c => {
      if (c.id !== cultoId) return c;
      if (role === 'abertura') return { ...c, workersAbertura: c.workersAbertura.filter(id => id !== obreiroId) };
      if (role === 'apoio') return { ...c, workersApoio: c.workersApoio.filter(id => id !== obreiroId) };
      return { ...c, santaCeiaWorkers: { ...(c.santaCeiaWorkers || { arrumarMesa: '', desarrumarMesa: '', servirPao: '', servirVinho: '' }), [role]: '' } };
    });
    updateDataWithNewCultos(updatedAll);
  };

  const handleAutoFillMonth = () => {
    if (data.obreiros.length < 2) return alert("Mínimo 2 obreiros.");
    if (cultosDoMes.length === 0) return alert("Gere a base primeiro.");

    setIsGenerating(true);

    // Trabalhamos com cópias locais para simular o processo
    let tempObreiros = JSON.parse(JSON.stringify(data.obreiros)) as Obreiro[];
    let allCultos = JSON.parse(JSON.stringify(data.cultos)) as Culto[];

    // Processamos apenas os cultos do mês atual que estão vazios
    allCultos.forEach((culto) => {
      const cDate = new Date(culto.date + "T12:00:00");
      if (cDate.getMonth() !== data.currentMonth || cDate.getFullYear() !== data.currentYear) return;

      const slotId = (culto.dayOfWeek === 0) ? (parseInt(culto.time.split(':')[0]) < 14 ? 0 : 7) : culto.dayOfWeek;

      const selectForRole = (target: 'abertura' | 'apoio') => {
        const currentList = target === 'abertura' ? culto.workersAbertura : culto.workersApoio;
        if (currentList.length >= 1) return;

        let candidates = tempObreiros.filter(o => !o.restrictions.includes(slotId) && !culto.workersAbertura.includes(o.id) && !culto.workersApoio.includes(o.id) && (o.preferredRole === target || o.preferredRole === 'ambos'));
        if (candidates.length === 0) candidates = tempObreiros.filter(o => !o.restrictions.includes(slotId) && !culto.workersAbertura.includes(o.id) && !culto.workersApoio.includes(o.id));
        if (candidates.length === 0) return;

        // Critério crucial: Pega quem tem o menor saldo GLOBAL (considerando meses passados)
        const minBal = Math.min(...candidates.map(o => o.balance));
        const eligible = candidates.filter(o => o.balance === minBal);
        const winner = eligible[Math.floor(Math.random() * eligible.length)];

        if (target === 'abertura') culto.workersAbertura.push(winner.id); else culto.workersApoio.push(winner.id);

        // Atualiza saldo na cópia local para os próximos cultos do mesmo loop
        const realObreiro = tempObreiros.find(o => o.id === winner.id);
        if (realObreiro) realObreiro.balance += 1;

        // Vínculo
        if (winner.linkedWorkerId) {
           const partner = tempObreiros.find(o => o.id === winner.linkedWorkerId);
           const otherRole = target === 'abertura' ? 'apoio' : 'abertura';
           const otherList = otherRole === 'abertura' ? culto.workersAbertura : culto.workersApoio;

           if (partner && !partner.restrictions.includes(slotId) && otherList.length === 0) {
             if (otherRole === 'abertura') culto.workersAbertura.push(partner.id); else culto.workersApoio.push(partner.id);
             partner.balance += 1;
           }
        }
      };

      selectForRole('abertura');
      selectForRole('apoio');
    });

    updateDataWithNewCultos(allCultos);
    setTimeout(() => { setIsGenerating(false); alert("Escala distribuída com sucesso!"); }, 600);
  };

  const filteredCultos = cultosDoMes.filter(culto => {
    if (!searchTerm) return true;
    const s = searchTerm.toLowerCase();
    const getObreiroName = (id: string) => data.obreiros.find(o => o.id === id)?.name.toLowerCase() || '';
    const names = [...culto.workersAbertura, ...culto.workersApoio].map(getObreiroName);
    return names.some(n => n.includes(s));
  });

  return (
    <div className="space-y-6 pb-20">
      {/* Navegador de Meses */}
      <div className="bg-white p-4 rounded-[32px] shadow-sm border border-slate-100 flex items-center justify-between gap-2">
        <button onClick={() => setData(prev => ({...prev, currentMonth: prev.currentMonth === 0 ? 11 : prev.currentMonth - 1, currentYear: prev.currentMonth === 0 ? prev.currentYear - 1 : prev.currentYear}))} className="p-3 bg-slate-50 rounded-2xl text-slate-400 hover:text-blue-600 transition-colors">
          <ChevronLeft size={24} />
        </button>
        <div className="flex flex-col items-center">
           <div className="flex gap-2">
             <select value={data.currentMonth} onChange={handleMonthChange} className="bg-transparent font-black text-xl text-blue-950 uppercase outline-none appearance-none cursor-pointer">{MONTHS.map((m, i) => <option key={m} value={i}>{m}</option>)}</select>
             <select value={data.currentYear} onChange={handleYearChange} className="bg-transparent font-black text-xl text-blue-950 outline-none appearance-none cursor-pointer">{years.map(y => <option key={y} value={y}>{y}</option>)}</select>
           </div>
           <span className="text-[9px] font-black text-blue-400 uppercase tracking-widest">{cultosDoMes.length} CULTOS REGISTRADOS</span>
        </div>
        <button onClick={() => setData(prev => ({...prev, currentMonth: prev.currentMonth === 11 ? 0 : prev.currentMonth + 1, currentYear: prev.currentMonth === 11 ? prev.currentYear + 1 : prev.currentYear}))} className="p-3 bg-slate-50 rounded-2xl text-slate-400 hover:text-blue-600 transition-colors">
          <ChevronRight size={24} />
        </button>
      </div>

      <div className="bg-white p-6 rounded-[40px] shadow-sm border border-slate-100">
        <div className="grid grid-cols-2 gap-3 mb-6">
          <button onClick={handleGenerateBase} className="bg-blue-50 text-blue-700 border border-blue-100 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2">
            <Plus size={16} /> Base {MONTHS[data.currentMonth]}
          </button>
          <button onClick={() => setShowAddManual(true)} className="bg-slate-900 text-white py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2">
            <CalendarDays size={16} /> Novo Culto
          </button>
        </div>

        <div className="relative mb-6">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
          <input type="text" placeholder="Filtrar nesta lista..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-slate-900 outline-none" />
        </div>

        {cultosDoMes.length > 0 && !searchTerm && (
          <div className="flex flex-col gap-3">
            <button onClick={handleAutoFillMonth} disabled={isGenerating} className={`w-full py-6 rounded-[24px] text-white font-black flex items-center justify-center gap-4 shadow-xl transition-all ${isGenerating ? 'bg-slate-400' : 'bg-blue-900'}`}>
              <Wand2 size={24} /> {isGenerating ? 'PROCESSANDO...' : 'DISTRIBUIR NESTE MÊS'}
            </button>
            <button onClick={handleClearMonth} className="w-full py-3 text-slate-400 font-black text-[9px] uppercase tracking-[0.2em] flex items-center justify-center gap-2">
              <RefreshCw size={14} /> Limpar {MONTHS[data.currentMonth]}
            </button>
          </div>
        )}
      </div>

      <div className="space-y-4">
        {filteredCultos.length === 0 ? (
          <div className="text-center py-20 text-slate-200 font-black uppercase tracking-widest italic">Nenhum culto para este período</div>
        ) : (
          filteredCultos.map((culto) => (
            <div key={culto.id} className="bg-white p-6 rounded-[48px] border border-slate-100 shadow-sm">
              <div className="flex justify-between items-start mb-6">
                <div>
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-[10px] font-black bg-blue-900 text-white px-3 py-1 rounded-full">{culto.date.split('-').reverse().join('/')}</span>
                    <span className={`text-[10px] font-black px-3 py-1 rounded-full ${culto.isSantaCeia ? 'bg-purple-100 text-purple-700' : 'bg-slate-100 text-slate-500'}`}>{culto.name.toUpperCase()}</span>
                  </div>
                  <h4 className="font-black text-slate-900 text-xl uppercase tracking-tighter">{DAYS_FULL[culto.dayOfWeek]} • {culto.time}H</h4>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => {
                    const updated = data.cultos.map(c => c.id === culto.id ? {...c, isSantaCeia: !c.isSantaCeia} : c);
                    setData(prev => ({...prev, cultos: updated}));
                  }} className={`p-4 rounded-2xl border transition-all ${culto.isSantaCeia ? 'bg-purple-600 border-purple-600 text-white shadow-lg' : 'bg-slate-50 border-slate-100 text-slate-300'}`}><Wine size={20} /></button>
                  <button onClick={() => {
                    if(confirm("Remover este culto?")) updateDataWithNewCultos(data.cultos.filter(c => c.id !== culto.id));
                  }} className="p-4 bg-slate-50 text-slate-300 rounded-2xl border border-slate-100 hover:text-rose-500"><Trash2 size={20} /></button>
                </div>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="bg-blue-50/40 p-4 rounded-[32px] border border-blue-50/50">
                  <span className="text-[9px] font-black text-blue-900 uppercase block mb-3">Abertura</span>
                  {culto.workersAbertura.map(wid => (
                    <div key={wid} className="bg-white p-3 rounded-xl border border-blue-100 flex justify-between items-center mb-2 shadow-sm">
                      <span className="text-xs font-black text-slate-900 uppercase">{data.obreiros.find(x => x.id === wid)?.name}</span>
                      <button onClick={() => removeWorker(culto.id, wid, 'abertura')} className="text-rose-400 hover:text-rose-600"><X size={16} /></button>
                    </div>
                  ))}
                  {culto.workersAbertura.length === 0 && <button onClick={() => setShowPicker({ cultoId: culto.id, role: 'abertura' })} className="w-full py-3 border-2 border-dashed border-blue-200 rounded-xl text-[10px] font-black text-blue-300 uppercase hover:bg-blue-50/50 transition-colors">+ Abertura</button>}
                </div>
                <div className="bg-emerald-50/40 p-4 rounded-[32px] border border-emerald-50/50">
                  <span className="text-[9px] font-black text-emerald-900 uppercase block mb-3">Apoio</span>
                  {culto.workersApoio.map(wid => (
                    <div key={wid} className="bg-white p-3 rounded-xl border border-emerald-100 flex justify-between items-center mb-2 shadow-sm">
                      <span className="text-xs font-black text-slate-900 uppercase">{data.obreiros.find(x => x.id === wid)?.name}</span>
                      <button onClick={() => removeWorker(culto.id, wid, 'apoio')} className="text-rose-400 hover:text-rose-600"><X size={16} /></button>
                    </div>
                  ))}
                  {culto.workersApoio.length === 0 && <button onClick={() => setShowPicker({ cultoId: culto.id, role: 'apoio' })} className="w-full py-3 border-2 border-dashed border-emerald-200 rounded-xl text-[10px] font-black text-emerald-300 uppercase hover:bg-emerald-50/50 transition-colors">+ Apoio</button>}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {showPicker && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="font-black uppercase tracking-tighter">Selecionar Obreiro</h3><button onClick={() => setShowPicker(null)} className="p-2 hover:bg-white/10 rounded-full"><X size={24} /></button></div>
            <div className="p-4 max-h-[60vh] overflow-y-auto space-y-2">
              <div className="p-2 text-[8px] font-black text-slate-300 uppercase tracking-[0.2em] mb-2 text-center">Saldos Globais (Incluso meses anteriores)</div>
              {data.obreiros.sort((a,b) => a.balance - b.balance || a.name.localeCompare(b.name)).map(o => (
                <button key={o.id} onClick={() => assignWorker(showPicker.cultoId, o.id, showPicker.role)} className="w-full p-4 flex justify-between items-center rounded-2xl border border-slate-100 hover:bg-slate-50 transition-colors group">
                  <div className="text-left">
                    <span className="text-[9px] font-black text-slate-400 uppercase block leading-none">{o.role}</span>
                    <span className="font-black text-slate-900 uppercase text-sm group-hover:text-blue-600">{o.name}</span>
                  </div>
                  <div className="text-right">
                    <span className="text-xs font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-full">{o.balance}</span>
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {showAddManual && (
        <div className="fixed inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[40px] shadow-2xl overflow-hidden animate-in zoom-in-95">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center"><h3 className="font-black uppercase tracking-tighter">Novo Culto</h3><button onClick={() => setShowAddManual(false)} className="p-2 hover:bg-white/10 rounded-full"><X size={24} /></button></div>
            <div className="p-6 space-y-4">
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Data</label>
                <input type="date" value={newCulto.date} onChange={e => setNewCulto({...newCulto, date: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none" />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Horário</label>
                <input type="time" value={newCulto.time} onChange={e => setNewCulto({...newCulto, time: e.target.value})} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none" />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Nome do Evento</label>
                <input type="text" value={newCulto.name} onChange={e => setNewCulto({...newCulto, name: e.target.value})} placeholder="EX: CULTO DE DOUTRINA" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold outline-none uppercase" />
              </div>
              <button onClick={handleAddManual} className="w-full py-5 bg-blue-900 text-white rounded-[24px] font-black uppercase tracking-widest shadow-xl mt-4">Adicionar Culto</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GerenciarMesTab;

import React, { useRef, useState, useMemo } from 'react';
import { Key, Users, Search, X, Smartphone, Printer, Share2, CalendarDays, FileDown, ChevronLeft, ChevronRight, Zap, ShieldCheck, Quote } from 'lucide-react';
import { AppDataV1, Culto } from '../types';
import { MONTHS, DAYS_SHORT } from '../constants';

interface Props {
  data: AppDataV1;
}

const RelatorioTab: React.FC<Props> = ({ data }) => {
  const [isExporting, setIsExporting] = useState(false);
  const [filterName, setFilterName] = useState('');
  const [viewMode, setViewMode] = useState<'print' | 'mobile' | 'weekly'>('weekly');
  const [selectedWeek, setSelectedWeek] = useState(0);

  const reportRef = useRef<HTMLDivElement>(null);
  const mobileRef = useRef<HTMLDivElement>(null);
  const weeklyRef = useRef<HTMLDivElement>(null);

  const WHATSAPP_MESSAGE = "Paz, obreiros. Segue a escala. Deus abençoe!";

  const getWorkerDisplayName = (id: string | undefined) => {
    if (!id) return '---';
    const obreiro = data.obreiros.find(o => o.id === id);
    if (!obreiro) return '---';
    const name = obreiro.name.split(' ')[0] + (obreiro.name.split(' ')[1] ? ' ' + obreiro.name.split(' ')[1][0] + '.' : '');
    return `${obreiro.role} ${name}`.toUpperCase();
  };

  // Filtra apenas cultos do MÊS ATUAL selecionado no estado global
  const sortedCultos = useMemo(() => {
    return [...data.cultos]
      .filter(c => {
        const d = new Date(c.date + "T12:00:00");
        return d.getMonth() === data.currentMonth && d.getFullYear() === data.currentYear;
      })
      .sort((a, b) => a.date.localeCompare(b.date) || a.time.localeCompare(b.time))
      .filter(culto => {
        if (!filterName) return true;
        const f = filterName.toLowerCase();
        const namesInCulto = [
          ...culto.workersAbertura.map(id => data.obreiros.find(o => o.id === id)?.name.toLowerCase() || ''), 
          ...culto.workersApoio.map(id => data.obreiros.find(o => o.id === id)?.name.toLowerCase() || '')
        ];
        return namesInCulto.some(name => name.includes(f));
      });
  }, [data.cultos, data.obreiros, filterName, data.currentMonth, data.currentYear]);

  const weeks = useMemo(() => {
    if (sortedCultos.length === 0) return [];
    const weeksMap = new Map<string, Culto[]>();
    sortedCultos.forEach(culto => {
      const d = new Date(culto.date + "T12:00:00");
      const day = d.getDay(); 
      const diffToMonday = day === 0 ? 6 : day - 1;
      const monday = new Date(d);
      monday.setDate(d.getDate() - diffToMonday);
      const weekKey = monday.toISOString().split('T')[0];
      if (!weeksMap.has(weekKey)) weeksMap.set(weekKey, []);
      weeksMap.get(weekKey)?.push(culto);
    });
    return Array.from(weeksMap.keys()).sort().map(key => weeksMap.get(key) || []);
  }, [sortedCultos]);

  const cultosToShow = viewMode === 'weekly' ? (weeks[selectedWeek] || []) : sortedCultos;

  const weekRangeLabel = useMemo(() => {
    if (viewMode !== 'weekly' || !cultosToShow.length) return "";
    const baseDate = new Date(cultosToShow[0].date + "T12:00:00");
    const day = baseDate.getDay();
    const diffToMonday = day === 0 ? 6 : day - 1;
    const mon = new Date(baseDate);
    mon.setDate(baseDate.getDate() - diffToMonday);
    const sun = new Date(mon);
    sun.setDate(mon.getDate() + 6);
    const mStart = MONTHS[mon.getMonth()].toUpperCase();
    if (mon.getMonth() !== sun.getMonth()) return `${mon.getDate()}/${mon.getMonth()+1} a ${sun.getDate()}/${sun.getMonth()+1}`;
    return `${mon.getDate()} a ${sun.getDate()} DE ${mStart}`;
  }, [cultosToShow, viewMode]);

  const handleExportPDF = () => {
    const element = viewMode === 'print' ? reportRef.current : (viewMode === 'mobile' ? mobileRef.current : weeklyRef.current);
    if (!element) return;
    setIsExporting(true);
    const filename = `ESCALA_ADFARE_${MONTHS[data.currentMonth].toUpperCase()}.pdf`;
    const opt = {
      margin: [5, 5],
      filename: filename,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'px', format: viewMode === 'print' ? 'a4' : [400, 800], orientation: 'portrait' }
    };
    // @ts-ignore
    if (typeof html2pdf !== 'undefined') {
      // @ts-ignore
      html2pdf().from(element).set(opt).save().then(() => setIsExporting(false)).catch(() => setIsExporting(false));
    } else {
      setIsExporting(false);
    }
  };

  const handleExportImage = async () => {
    const element = viewMode === 'weekly' ? weeklyRef.current : mobileRef.current;
    if (!element) return;
    setIsExporting(true);

    // @ts-ignore
    if (typeof html2canvas !== 'undefined') {
      // @ts-ignore
      html2canvas(element, {
        scale: 3,
        useCORS: true,
        backgroundColor: "#ffffff",
        logging: false,
        width: 400,
      }).then(async (canvas) => {
        const fileName = `ESCALA_ADFARE_${viewMode.toUpperCase()}.png`;
        canvas.toBlob(async (blob: Blob | null) => {
          if (!blob) { setIsExporting(false); return; }
          const file = new File([blob], fileName, { type: 'image/png' });
          // @ts-ignore
          if (navigator.canShare && navigator.canShare({ files: [file] })) {
            try { await navigator.share({ files: [file], title: 'Escala ADFARE', text: WHATSAPP_MESSAGE }); } 
            catch (err) { downloadImage(canvas, fileName); }
          } else {
            downloadImage(canvas, fileName);
          }
          setIsExporting(false);
        }, 'image/png');
      }).catch(() => setIsExporting(false));
    } else {
      setIsExporting(false);
    }
  };

  const downloadImage = (canvas: HTMLCanvasElement, fileName: string) => {
    const link = document.createElement('a');
    link.download = fileName;
    link.href = canvas.toDataURL('image/png', 1.0);
    link.click();
  };

  const renderDigitalLayout = (ref: React.RefObject<HTMLDivElement>, id: string, title: string, dateLabel: string, cultos: Culto[]) => (
    <div 
      ref={ref} 
      id={id} 
      className="bg-white w-full max-w-[400px] mx-auto flex flex-col p-4 shadow-sm relative overflow-hidden rounded-[24px] border border-slate-100"
    >
      <div className="bg-blue-950 rounded-[24px] p-5 text-white mb-6 border-b-4 border-blue-600 shadow-lg text-center">
         <span className="text-[8px] font-black tracking-[0.2em] text-blue-400 uppercase block mb-1">{title}</span>
         <h1 className="text-2xl font-black italic text-white uppercase leading-none mb-4">ADFARE</h1>
         <div className="bg-white/10 backdrop-blur-sm rounded-xl p-2.5 border border-white/10">
          <span className="text-sm font-black uppercase text-white block">
            {dateLabel}
          </span>
        </div>
      </div>

      <div className="space-y-3 mb-6">
        {cultos.length === 0 ? (
          <div className="py-10 text-center text-slate-300 font-black uppercase text-[10px] italic tracking-widest">Sem cultos para este período</div>
        ) : (
          cultos.map((culto) => (
            <div key={culto.id} className={`rounded-[20px] p-3 shadow-sm border ${culto.isSantaCeia ? 'bg-purple-900 border-purple-800 text-white' : 'bg-slate-50 border-slate-100'}`}>
              <div className="flex items-center gap-3">
                <div className={`w-12 h-12 rounded-xl flex flex-col items-center justify-center shrink-0 shadow-sm ${culto.isSantaCeia ? 'bg-white text-purple-900' : 'bg-blue-900 text-white'}`}>
                  <span className="text-[7px] font-black opacity-60 uppercase">{DAYS_SHORT[culto.dayOfWeek]}</span>
                  <span className="text-xl font-black leading-none">{culto.date.split('-')[2]}</span>
                </div>
                <div className="flex-grow min-w-0">
                  <div className="flex justify-between items-center mb-1.5">
                    <h4 className={`text-[11px] font-black uppercase truncate pr-2 ${culto.isSantaCeia ? 'text-white' : 'text-slate-800'}`}>{culto.isSantaCeia ? '★ CEIA' : culto.name}</h4>
                    <span className={`shrink-0 text-[9px] font-black px-2 py-0.5 rounded-md ${culto.isSantaCeia ? 'bg-purple-800 text-white' : 'bg-white text-blue-900'}`}>{culto.time}H</span>
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div className={`p-1.5 rounded-lg flex items-center gap-1.5 min-w-0 ${culto.isSantaCeia ? 'bg-white/10' : 'bg-white'}`}>
                      <Key size={10} className={culto.isSantaCeia ? 'text-purple-300' : 'text-blue-600'} />
                      <span className="text-[9px] font-black uppercase truncate">{getWorkerDisplayName(culto.workersAbertura[0])}</span>
                    </div>
                    <div className={`p-1.5 rounded-lg flex items-center gap-1.5 min-w-0 ${culto.isSantaCeia ? 'bg-white/10' : 'bg-white'}`}>
                      <Users size={10} className={culto.isSantaCeia ? 'text-purple-300' : 'text-emerald-600'} />
                      <span className="text-[9px] font-black uppercase truncate">{getWorkerDisplayName(culto.workersApoio[0])}</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          )
        ))}
      </div>
      <div className="text-center opacity-40">
        <span className="text-[7px] font-black text-slate-500 uppercase tracking-[0.3em]">FAMÍLIA RESTAURADA</span>
      </div>
    </div>
  );

  return (
    <div className="space-y-4 pb-20">
      <div className="bg-white p-3 rounded-2xl shadow-sm border border-slate-100 no-print space-y-3">
        <div className="flex bg-slate-100 p-1 rounded-xl">
          <button onClick={() => setViewMode('weekly')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${viewMode === 'weekly' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}>Semana</button>
          <button onClick={() => setViewMode('mobile')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${viewMode === 'mobile' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}>Mês</button>
          <button onClick={() => setViewMode('print')} className={`flex-1 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${viewMode === 'print' ? 'bg-white text-blue-900 shadow-sm' : 'text-slate-400'}`}>Mural</button>
        </div>

        {viewMode === 'weekly' && weeks.length > 0 && (
          <div className="flex items-center justify-between bg-blue-50 p-2 rounded-xl border border-blue-100">
            <button disabled={selectedWeek === 0} onClick={() => setSelectedWeek(w => Math.max(0, w - 1))} className="p-2 text-blue-900 disabled:opacity-20"><ChevronLeft size={20} /></button>
            <div className="text-center px-2 min-w-0">
              <span className="text-[10px] font-black text-blue-900 uppercase">Semana {selectedWeek + 1}</span>
              <p className="text-[8px] font-bold text-blue-400 uppercase mt-0.5 truncate">{weekRangeLabel}</p>
            </div>
            <button disabled={selectedWeek === weeks.length - 1} onClick={() => setSelectedWeek(w => Math.min(weeks.length - 1, w + 1))} className="p-2 text-blue-900 disabled:opacity-20"><ChevronRight size={20} /></button>
          </div>
        )}

        <div className="grid grid-cols-2 gap-2">
          <button onClick={handleExportPDF} disabled={isExporting || cultosToShow.length === 0} className="py-3 bg-blue-900 text-white rounded-xl font-black flex items-center justify-center gap-2 text-[10px] uppercase shadow-md">
             PDF
          </button>
          <button onClick={handleExportImage} disabled={isExporting || cultosToShow.length === 0 || viewMode === 'print'} className="py-3 bg-emerald-600 text-white rounded-xl font-black flex items-center justify-center gap-2 text-[10px] uppercase shadow-md">
             COMPARTILHAR
          </button>
        </div>
      </div>

      <div className="w-full flex justify-center px-1">
        {viewMode === 'weekly' && renderDigitalLayout(weeklyRef, 'weekly-export', 'ESCALA DA SEMANA', weekRangeLabel || '---', cultosToShow)}
        {viewMode === 'mobile' && renderDigitalLayout(mobileRef, 'mobile-export', 'ESCALA MENSAL', `${MONTHS[data.currentMonth].toUpperCase()} ${data.currentYear}`, sortedCultos)}
        {viewMode === 'print' && (
          <div className="w-full overflow-x-auto pb-10">
            <div className="bg-white border border-slate-200 p-6 mx-auto rounded-xl" style={{ width: '794px', minHeight: '1123px' }} ref={reportRef}>
               <div className="border-b-4 border-blue-900 pb-4 mb-6 flex justify-between items-end">
                  <h1 className="text-4xl font-black italic text-blue-950">ADFARE</h1>
                  <span className="text-lg font-black uppercase bg-blue-900 text-white px-4 py-1 rounded-full">{MONTHS[data.currentMonth]} {data.currentYear}</span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  {sortedCultos.map(culto => (
                    <div key={culto.id} className="border border-slate-100 p-4 rounded-xl flex items-center gap-4 bg-slate-50">
                      <div className="w-14 h-14 bg-blue-900 text-white flex flex-col items-center justify-center rounded-xl shrink-0">
                        <span className="text-[9px] font-bold">{DAYS_SHORT[culto.dayOfWeek]}</span>
                        <span className="text-2xl font-black">{culto.date.split('-')[2]}</span>
                      </div>
                      <div className="min-w-0">
                        <p className="text-[10px] font-black text-blue-950 uppercase truncate">{culto.name}</p>
                        <p className="text-[11px] font-bold text-slate-700">AB: {getWorkerDisplayName(culto.workersAbertura[0])}</p>
                        <p className="text-[11px] font-bold text-slate-700">AP: {getWorkerDisplayName(culto.workersApoio[0])}</p>
                      </div>
                    </div>
                  ))}
               </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default RelatorioTab;
